  RVTEST_SIGUPD_CSR_READ(CSR_MPMPDELEG, x11, SspmpSm_csr_cg_cp_mpmpdeleg_pmpnum_zero_zero_and_delegating, SspmpSm_csr_cg_cp_mpmpdeleg_pmpnum_zero_zero_and_delegating_str)

# pmpnum = 8
  LI(x10, 8)
  CSRW(CSR_MPMPDELEG, x10)
